What does this program print?

```cpp
#include <array>
#include <iostream>
struct Point { int x {}; int y {}; };
int main() {
    std::array<Point, 2> pts { 10, 20, 30, 40 };
    std::cout << pts[0].x << ' ' << pts[1].y << '\n';
    return 0;
}
```

What does this program print?

```cpp
#include <array>
#include <iostream>
struct RGB { int r {}; int g {}; int b {}; };
int main() {
    std::array<RGB, 2> colors { RGB{255, 0, 0}, RGB{0, 255, 0} };
    for (const RGB& c : colors) {
        std::cout << c.r + c.g + c.b << '\n';
    }
    return 0;
}
```
